-- statement 01
SELECT booking_reminders.id, booking_reminders.booking_id, booking_reminders.rule_id, booking_reminders.kind, booking_reminders.scheduled_for, booking_reminders.sent_at, booking_reminders.status, booking_reminders.attempt_count, booking_reminders.error, booking_reminders.created_at FROM booking_reminders JOIN bookings ON booking_reminders.booking_id = bookings.id LEFT OUTER JOIN reminder_rules ON booking_reminders.rule_id = reminder_rules.id WHERE booking_reminders.scheduled_for <= %(scheduled_for_1)s AND bookings.status = %(status_1)s AND (booking_reminders.status = %(status_2)s AND (booking_reminders.sent_at IS NULL OR booking_reminders.sent_at <= %(sent_at_1)s) OR booking_reminders.status = %(status_3)s AND coalesce(booking_reminders.attempt_count, %(coalesce_1)s) < coalesce(reminder_rules.max_sends, %(coalesce_2)s)) ORDER BY booking_reminders.scheduled_for ASC, booking_reminders.id ASC LIMIT %(param_1)s FOR UPDATE SKIP LOCKED;
